INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('ab28d8fa-be29-4fc0-9b7e-14f1379eaee0', 'Exogenetic PDRN Creme Facial 30g', 'exogenetic-pdrn-creme-facial-30g-7001', 'Creme facial que combina biotecnologia de ponta e ativos inovadores para manter a pele revitalizada, firme e luminosa, ajudando a retardar os sinais do tempo de forma contínua. Promove a longevidade da pele, recupera a energia celular e reduz linhas de expressão e rugas. Testado dermatologicamente com biotecnologia avançada. Rendimento: ± 37 aplicações.', 'Creme facial que combina biotecnologia de ponta e ativos inovadores para manter a pele revitalizada, firme e luminosa, ajudando a retardar os sinais do tempo de forma contínua.', 0.01, NULL, 'Tulipia', 'lancamentos', NULL, '/src/assets/products/tulipia/exogenetic-pdrn-official.png', ARRAY['/src/assets/products/tulipia/exogenetic-pdrn-uso.jpg', '/src/assets/products/tulipia/exogenetic-pdrn-textura.jpg', '/src/assets/products/tulipia/exogenetic-pdrn-tampa.jpg', '/src/assets/products/tulipia/exogenetic-pdrn.jpg']::text[], 100, 'HC-7001', true, false, true, ARRAY['home-care', 'PDRN', 'Exossomas', 'Peptídeos', 'NAD+', 'NMN', 'Ácido Hialurônico', 'Niacinamida']::text[], ARRAY['Anti-idade', 'Biotecnologia', 'Eficácia comprovada', 'Facial', 'Hidratação', 'Indicado para todos os tipos de pele', 'Nanotecnologia', 'Rugas', 'Testado Dermatologicamente']::text[], 'PDRN, Exossomas, Peptídeos, NAD+, NMN, Ácido Hialurônico, Niacinamida', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('46721b03-3439-47fb-a26f-d7ba52a1e0da', 'Niacine+ Espuma de Limpeza de Niacinamida 150ml', 'niacine-espuma-de-limpeza-de-niacinamida-150ml-7002', 'Uma espuma suave com Niacinamida, ativos hidratantes e pH fisiológico para uma limpeza delicada e precisa. Com ação probiótica, ajuda hidratar a pele, remove impurezas, oleosidade e mantém o conforto desde o primeiro uso.', 'Uma espuma suave com Niacinamida, ativos hidratantes e pH fisiológico para uma limpeza delicada e precisa. Com ação probiótica, ajuda hidratar a pele, remove impurezas, oleosidade e mantém o conforto desde o primeiro uso.', 94.90, NULL, 'Tulipia', 'lancamentos', NULL, '/src/assets/products/tulipia/niacine-espuma-official.png', ARRAY['/src/assets/products/tulipia/niacine-espuma-textura.jpg', '/src/assets/products/tulipia/niacine-espuma-produto.jpg', '/src/assets/products/tulipia/niacine-espuma-uso.jpg', '/src/assets/products/tulipia/niacine-espuma-masculino.jpg', '/src/assets/products/tulipia/niacine-espuma-frasco.jpg']::text[], 100, 'HC-7002', true, false, true, ARRAY['home-care', 'Alantoína', 'D-Pantenol', 'Lactobacillus', 'Nano Ácido Hialurônico', 'Nano Niacinamida', 'PCA de Sódio', 'Pullulan']::text[], ARRAY['Controle da oleosidade', 'Eficácia comprovada', 'Espuma de limpeza', 'Facial', 'Indicado para todos os tipos de pele', 'Nanotecnologia', 'Pré-biótico']::text[], 'Alantoína, D-Pantenol, Lactobacillus, Nano Ácido Hialurônico, Nano Niacinamida, PCA de Sódio, Pullulan', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
