INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('f80e30c7-3668-4287-978e-12bc79bb5114', 'Black Secret Peeling Antiacne 30ml', 'black-secret-peeling-antiacne-30ml-7010', 'Peeling profissional para tratamento de acne com Azeloglicina®. Reduz inflamação, controla oleosidade e clareia manchas pós-inflamatórias. Testado dermatologicamente.', 'Peeling profissional para tratamento de acne com Azeloglicina®. Reduz inflamação, controla oleosidade e clareia manchas pós-inflamatórias.', 199.86, NULL, 'Tulipia', 'clareamento', NULL, '/src/assets/products/tulipia/black-secret-antiacne-official.png', ARRAY['/src/assets/products/tulipia/black-secret-antiacne-agua.jpg', '/src/assets/products/tulipia/black-secret-antiacne-robo.jpg', '/src/assets/products/tulipia/black-secret-antiacne-aplicacao.jpg', '/src/assets/products/tulipia/black-secret-antiacne-familia.jpg', '/src/assets/products/tulipia/black-secret-antiacne-frasco.jpg']::text[], 100, 'HC-7010', true, false, false, ARRAY['profissional', 'Azeloglicina®', 'Ácido Succínico', 'Ácido Chiquímico', 'Ácido Glicirrízico', 'Ácido Salicílico', 'Ácido Lático', 'Ácido Glicólico', 'Centella Asiática', 'Pantenol']::text[], ARRAY['Acne', 'Calmante', 'Cicatrizes de acne', 'Clareamento e uniformização da pele', 'Controle da oleosidade', 'Eficácia comprovada', 'Exclusivo para profissional', 'Facial', 'Indicado para todos os tipos de pele', 'Nanotecnologia', 'Testado Dermatologicamente']::text[], 'Azeloglicina®, Ácido Succínico, Ácido Chiquímico, Ácido Glicirrízico, Ácido Salicílico, Ácido Lático, Ácido Glicólico, Centella Asiática, Pantenol', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('44b3b31d-61f3-4fe7-9813-fcaf82dea97e', 'Verão Mask Nano Máscara Energizante 150g', 'verao-mask-nano-mascara-energizante-150g-7041', 'Verão, a estação da vida! Alegre convite para um banho de hidratação com um coquetel de nutrientes que despertam a energia celular, devolvendo à pele seu vigor, maciez e brilho. Uma face resplandecente como um dia ensolarado. Ideal para todos os tipos de pele e coadjuvante em protocolos de hidratação e revitalização pós-sol. Rendimento: ± 30 aplicações.', 'Coquetel refrescante de frutas tropicais e algas marinhas que despertam a energia celular, devolvendo vigor, maciez e brilho.', 141.43, NULL, 'Tulipia', 'mascara', NULL, '/src/assets/products/tulipia/verao-mask-hero.png', ARRAY['/src/assets/products/tulipia/verao-mask.jpg']::text[], 100, 'HC-7041', true, false, false, ARRAY['profissional', 'Extrato de Manga', 'Extrato de Maracujá', 'Extrato de Grapefruit', 'Algas Marinhas', 'Ácido Hialurônico', 'Nano Lift', 'Óleo de Coco', 'Óleo de Girassol']::text[], ARRAY[]::text[], 'Extrato de Manga, Extrato de Maracujá, Extrato de Grapefruit, Algas Marinhas, Ácido Hialurônico, Nano Lift, Óleo de Coco, Óleo de Girassol', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('4c5b48d0-d323-4b30-93a1-899e9344d900', 'Black Secret Peeling Facial 2 Fases', 'black-secret-peeling-facial-2-fases-7011', 'O Black Secret Peeling Facial é a nova geração dos peelings profissionais. Com tecnologia e ativos consagrados pela ciência dermocosmética, sua fórmula inovadora traz o equilíbrio entre segurança e performance, unindo a esfoliação química, física e enzimática a um blend clareador de alta potência. Clareia com precisão, além de atuar sobre a textura irregular e sinais de envelhecimento, inclusive linhas finas e marcas. A descamação controlada garante segurança e eficácia, promovendo uma pele mais luminosa, uniforme, sem marcas e rejuvenescida em poucas sessões.', 'O segredo de profissional para profissional. A nova geração dos peelings profissionais com esfoliação química, física e enzimática.', 714.14, NULL, 'Tulipia', 'clareamento', NULL, '/src/assets/products/tulipia/black-secret-2fases-official.png', ARRAY['/src/assets/products/tulipia/black-secret-peeling-2-fases.jpg', '/src/assets/products/tulipia/black-secret-antes-1.jpg', '/src/assets/products/tulipia/black-secret-depois-1.jpg', '/src/assets/products/tulipia/black-secret-antes-2.jpg', '/src/assets/products/tulipia/black-secret-depois-2.jpg']::text[], 100, 'HC-7011', true, false, false, ARRAY['profissional', 'Epicuticle®', 'Papaína', 'Bromelina', 'Ácido Glicólico', 'Ácido Salicílico', 'Cristais de Quartzo', 'Retinol', 'Brightenyl®', 'Ácido Diglicosil Gálico', 'Cybright®', 'Ácido Kójico']::text[], ARRAY['Clareamento e uniformização da pele', 'Eficácia comprovada', 'Esfoliação', 'Exclusivo para profissional', 'Facial', 'Nanotecnologia', 'Peeling', 'Rugas']::text[], 'Epicuticle®, Papaína, Bromelina, Ácido Glicólico, Ácido Salicílico, Cristais de Quartzo, Retinol, Brightenyl®, Ácido Diglicosil Gálico, Cybright®, Ácido Kójico', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('c94a3c81-85cc-425c-8151-648e1a73df83', 'Black Secret Sabonete Glico-Renovador 300ml', 'black-secret-sabonete-glico-renovador-300ml-7012', 'O sabonete glico-renovador Black Secret é um sabonete rico em Ácido Glicólico que promove limpeza profunda, esfoliação química leve e segura, revitalização e uniformização da pele, para uma pele visivelmente mais macia e luminosa já nas primeiras aplicações. Promove uma limpeza profunda da pele, desobstruindo os poros e eliminando os detritos celulares e poluição. Realiza um importante afinamento da capa córnea, potencializando os tratamentos estéticos faciais e corporais.', 'Sabonete rico em Ácido Glicólico que promove limpeza profunda, esfoliação química leve e segura, revitalização e uniformização da pele.', 180.00, NULL, 'Tulipia', 'clareamento', NULL, '/src/assets/products/tulipia/black-secret-sabonete-official.png', ARRAY['/src/assets/products/tulipia/black-secret-sabonete-glico.jpg', '/src/assets/products/tulipia/black-secret-sabonete-glico-produto.jpg']::text[], 100, 'HC-7012', true, false, false, ARRAY['home-care', 'Ácido Glicólico 10%', 'Gluconolactona', 'Ácido Lactobiônico', 'Extrato de Pepino', 'Lactato de Mentila', 'Nano Acids', 'Ácido Cítrico', 'Ácido Láctico', 'Extrato de Juá']::text[], ARRAY['Clareamento e uniformização da pele', 'Esfoliação', 'Facial e Corporal', 'Indicado para todos os tipos de pele', 'Limpeza profunda', 'Nanotecnologia']::text[], 'Ácido Glicólico 10%, Gluconolactona, Ácido Lactobiônico, Extrato de Pepino, Lactato de Mentila, Nano Acids, Ácido Cítrico, Ácido Láctico, Extrato de Juá', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('f7eda9ce-34c1-49c7-94c8-1084f39b8d66', 'Black Secret Solução Pré-Peeling Desengordurante 120ml', 'black-secret-solucao-pre-peeling-desengordurante-120ml-7013', 'Concentrado de ativos purificantes e nanopartículas, esta solução não somente remove a oleosidade e impurezas da pele, mas potencializa o processo de renovação celular, deixando-a profundamente limpa e com uma agradável sensação de frescor. Sua utilização, especialmente nas peles oleosas e seborreicas, permite um preparo perfeito para os procedimentos estéticos, aumentando significativamente a receptividade dos cosméticos de tratamento.', 'Concentrado de ativos purificantes e nanopartículas que remove oleosidade e potencializa a renovação celular.', 170.00, NULL, 'Tulipia', 'clareamento', NULL, '/src/assets/products/tulipia/black-secret-prepeeling-official.png', ARRAY['/src/assets/products/tulipia/black-secret-solucao-pre-peeling.jpg', '/src/assets/products/tulipia/black-secret-solucao-pre-peeling-produto.jpg']::text[], 100, 'HC-7013', true, false, false, ARRAY['profissional', 'Ácido Glicólico 10%', 'Nano Acids', 'Ácido Cítrico', 'Ácido Láctico', 'Acetona', 'Mentol']::text[], ARRAY['Controle da oleosidade', 'Exclusivo para profissional', 'Facial', 'Limpeza profunda', 'Nanotecnologia', 'Pré-Peeling']::text[], 'Ácido Glicólico 10%, Nano Acids, Ácido Cítrico, Ácido Láctico, Acetona, Mentol', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('6a031b43-b896-48b8-8be8-422e50c0032f', 'Black Secret Clareador Concentrado 60ml', 'black-secret-clareador-concentrado-60ml-7014', 'Com uma combinação sinérgica de ácidos, este concentrado auxilia no clareamento e na uniformização do tom da pele, contribuindo para a melhora da aparência de áreas escurecidas. Proporciona textura suavizada, luminosidade e conforto, promovendo o equilíbrio cutâneo. Ideal para protocolos de manutenção da pele e para cuidados com áreas escurecidas, sem causar descamação ou vermelhidão perceptível.', 'Concentrado com blend de ácidos clareadores que auxilia na uniformização do tom da pele e suaviza áreas escurecidas.', 199.00, NULL, 'Tulipia', 'clareamento', NULL, '/src/assets/products/tulipia/black-secret-clareador-official.png', ARRAY['/src/assets/products/tulipia/black-secret-clareador.jpg', '/src/assets/products/tulipia/black-secret-clareador-produto.jpg']::text[], 100, 'HC-7014', true, false, false, ARRAY['home-care', 'Ácido Fítico', 'Ácido Glicólico', 'Ácido Kójico', 'Ácido Mandélico', 'Ácido Tranexâmico', 'Alantoína', 'Nicotinamida']::text[], ARRAY['Clareamento e uniformização da pele', 'Facial e Corporal', 'Indicado para todos os tipos de pele', 'Manchas', 'Nanotecnologia']::text[], 'Ácido Fítico, Ácido Glicólico, Ácido Kójico, Ácido Mandélico, Ácido Tranexâmico, Alantoína, Nicotinamida', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('1bc7e016-997e-40e0-9f7f-d027bc39c0de', 'Black Secret Micro Spikes Peeling 30g', 'black-secret-micro-spikes-peeling-30g-7015', 'Peeling profissional com microespículas naturais de esponja que potencializam a permeação de ativos, esfoliam, regeneram e iluminam o tom da pele. Uniformiza e promove renovação celular intensa com tecnologia Drone Copper e ativos de alta performance.', 'Peeling com microespículas naturais que potencializa a permeação de ativos, esfolia, regenera e ilumina o tom da pele.', 220.00, NULL, 'Tulipia', 'clareamento', NULL, '/src/assets/products/tulipia/black-secret-micro-spikes-hero.jpg', ARRAY['/src/assets/products/tulipia/black-secret-micro-spikes-pedra.jpg', '/src/assets/products/tulipia/black-secret-micro-spikes.jpg']::text[], 100, 'HC-7015', true, false, false, ARRAY['profissional', 'Micro Spikes', 'Drone Copper', 'Nano Ácido Tranexâmico', 'Esqualano Vegetal', 'Ácido Poliglutâmico', 'Manteiga de Tucumã', 'Vitamina E']::text[], ARRAY[]::text[], 'Micro Spikes, Drone Copper, Nano Ácido Tranexâmico, Esqualano Vegetal, Ácido Poliglutâmico, Manteiga de Tucumã, Vitamina E', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
