INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('d4ef5aa7-fb89-4028-9847-f573c336080b', 'Biowhite Nano Loção Clareadora 60ml', 'biowhite-nano-locao-clareadora-60ml-7016', 'A Nano Loção Clareadora Biowhite possui ação rejuvenescedora e clareadora na pele. Com o ativo Nano Hydroxy Acids em sua composição, estimula a síntese de colágeno, promove firmeza e reduz rugas e linhas de expressão. Por seu efeito clareador prolongado, a Biowhite não só suaviza as marcas escurecidas como também ajuda a prevenir seu reaparecimento ao longo do tempo. Resultados comprovados: 85% de melhora no clareamento da pele, 80% na uniformização do tom e 75% na firmeza.', 'Loção com Nano Hydroxy Acids que estimula a síntese de colágeno, promove firmeza, clareia e uniformiza o tom da pele.', 149.00, NULL, 'Tulipia', 'clareamento', NULL, '/src/assets/products/tulipia/biowhite-hero.jpg', ARRAY['/src/assets/products/tulipia/biowhite-uso.jpg', '/src/assets/products/tulipia/biowhite-frasco.jpg', '/src/assets/products/tulipia/black-biowhite-locao.jpg']::text[], 100, 'HC-7016', true, false, false, ARRAY['home-care', 'Nano Hydroxy Acids', 'Nano Up Lift', 'Ácido Kójico', 'Ácido Mandélico', 'Ácido Glicólico', 'Ácido Láctico', 'Ácido Cítrico', 'Ácido Fítico', 'Ácido Hialurônico', 'Extrato de Acácia do Senegal', 'Extrato de Alcaçuz', 'Óleo de Aveia']::text[], ARRAY[]::text[], 'Nano Hydroxy Acids, Nano Up Lift, Ácido Kójico, Ácido Mandélico, Ácido Glicólico, Ácido Láctico, Ácido Cítrico, Ácido Fítico, Ácido Hialurônico, Extrato de Acácia do Senegal, Extrato de Alcaçuz, Óleo de Aveia', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('df3fcb7c-fa6b-4151-a37e-78fd39d7ed3a', 'ProSkin Repair Sabonete Restaurador 110ml', 'proskin-repair-sabonete-restaurador-110ml-7020', 'Sabonete restaurador que limpa suavemente sem agredir a barreira cutânea, preservando a hidratação natural da pele. Ideal para peles sensibilizadas, fortalece e repara a barreira cutânea, previne sinais de envelhecimento e acalma a pele intensamente.', 'Limpa suavemente sem agredir a barreira cutânea, preservando a hidratação natural da pele.', 79.90, NULL, 'Tulipia', 'barreira-cutanea', NULL, '/src/assets/products/tulipia/proskin-sabonete-novo.jpg', ARRAY['/src/assets/products/tulipia/proskin-sabonete-lifestyle.jpg', '/src/assets/products/tulipia/proskin-sabonete-uso.jpg', '/src/assets/products/tulipia/proskin-sabonete-textura.jpg', '/src/assets/products/tulipia/proskin-sabonete.jpg']::text[], 100, 'HC-7020', true, false, false, ARRAY['home-care', 'Hydra H+', 'Ácido Hialurônico', 'Extrato de Lótus', 'NanoCurcuma™', 'Symbiocaps LA', 'Ecodermist', 'BioEcolia®', 'Oligossacarídeo Alfa-Glucan', 'BisaboLife™']::text[], ARRAY[]::text[], 'Hydra H+, Ácido Hialurônico, Extrato de Lótus, NanoCurcuma™, Symbiocaps LA, Ecodermist, BioEcolia®, Oligossacarídeo Alfa-Glucan, BisaboLife™', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
