INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('9f9dc96c-e596-42a3-b83e-426a6b33eb94', 'Outono Mask Nano Máscara Reequilibrante 150g', 'outono-mask-nano-mascara-reequilibrante-150g-7040', 'Máscara nutritiva, retexturizadora, detox e antioxidante que fortalece e condiciona a pele, proporcionando textura suave e aparência descansada. Ideal para todos os tipos de pele, especialmente aquelas afetadas por poluição ou tabagismo. Rendimento: ± 30 aplicações.', 'Sinta o alento renovador dessa máscara, que liberta a pele de radicais livres, assim como o cair das folhas secas no outono.', 141.43, NULL, 'Tulipia', 'mascara', NULL, '/src/assets/products/tulipia/outono-mask-hero.png', ARRAY['/src/assets/products/tulipia/outono-mask.jpg']::text[], 100, 'HC-7040', true, false, false, ARRAY['profissional', 'Ácido Hialurônico', 'Alantoína', 'Algisium C2', 'Cera de Carnaúba', 'Colágeno Hidrolisado', 'Extrato de Chá Verde', 'Extrato de Figo', 'Manteiga de Cupuaçu', 'Nano Hydrolift', 'Óleo de Semente de Uva']::text[], ARRAY[]::text[], 'Ácido Hialurônico, Alantoína, Algisium C2, Cera de Carnaúba, Colágeno Hidrolisado, Extrato de Chá Verde, Extrato de Figo, Manteiga de Cupuaçu, Nano Hydrolift, Óleo de Semente de Uva', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
