INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('3477c555-0c3c-4473-91a8-e6a0c68f0214', 'Inverno Mask Nano Máscara Hidronutritiva 150g', 'inverno-mask-nano-mascara-hidronutritiva-150g-7042', 'Inverno, tempo de repousar! Desfrute do aconchego dessa máscara, que abraça a pele como um manto protetor, permitindo-a restaurar sua barreira de proteção natural. Com ativos que recriam as reservas hídricas e nutricionais no interior da pele enquanto protegem a superfície, trazendo conforto e maciez. Ideal para todos os tipos de pele e coadjuvante em tratamentos de peles expostas a mudanças climáticas. Rendimento: ± 30 aplicações.', 'Desfrute do aconchego dessa máscara, que abraça a pele como um manto protetor, permitindo-a restaurar sua barreira de proteção natural.', 141.43, NULL, 'Tulipia', 'mascara', NULL, '/src/assets/products/tulipia/inverno-mask-hero.png', ARRAY['/src/assets/products/tulipia/inverno-mask.jpg']::text[], 100, 'HC-7042', true, false, false, ARRAY['profissional', 'Mica', 'Calcidone®', 'Colágeno Hidrolisado', 'Manteiga de Cupuaçu', 'Cera de Carnaúba', 'Nano Lift', 'Extrato de Aveia', 'Óleo de Gérmen de Trigo', 'Extrato de Levedo', 'Ácido Hialurônico']::text[], ARRAY[]::text[], 'Mica, Calcidone®, Colágeno Hidrolisado, Manteiga de Cupuaçu, Cera de Carnaúba, Nano Lift, Extrato de Aveia, Óleo de Gérmen de Trigo, Extrato de Levedo, Ácido Hialurônico', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('9461afac-9026-491f-baa9-6090ba5ad871', 'Primavera Mask Nano Máscara Renovadora 150g', 'primavera-mask-nano-mascara-renovadora-150g-7043', 'Primavera, a estação dos recomeços! Presenteie sua pele com uma fusão de ingredientes que revitalizam e transformam a textura e radiância, deixando-a macia e aveludada como uma pétala de rosa. Um novo rosto se revela, mais claro, luminoso, resplandecente. Ideal para todos os tipos de pele como coadjuvante em protocolos de hidratação e clareamento. Rendimento: ± 30 aplicações.', 'Presenteie sua pele com uma fusão de ingredientes que revitalizam e transformam a textura e radiância, deixando-a macia e aveludada como uma pétala de rosa.', 141.43, NULL, 'Tulipia', 'mascara', NULL, '/src/assets/products/tulipia/primavera-mask-hero.png', ARRAY['/src/assets/products/tulipia/primavera-mask.jpg']::text[], 100, 'HC-7043', true, false, false, ARRAY['profissional', 'Extrato Hidroglicólico de Hibiscus', 'Ácido Hialurônico', 'Colágeno Hidrolisado', 'Nano Hydrolift', 'Extrato de Orquídea', 'Extrato de Maracujá', 'Proteína do Leite']::text[], ARRAY[]::text[], 'Extrato Hidroglicólico de Hibiscus, Ácido Hialurônico, Colágeno Hidrolisado, Nano Hydrolift, Extrato de Orquídea, Extrato de Maracujá, Proteína do Leite', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('a0232438-609d-4c48-bde0-fe3a0b4bf6db', 'Stellar Mask Enzimática 100g', 'stellar-mask-enzimatica-100g-7044', 'A Máscara Enzimática foi desenvolvida para o uso profissional estético. Com a combinação de ativos naturais, essa máscara proporciona uma esfoliação eficaz, capaz de remover células mortas e preparar a pele para a absorção otimizada de ativos.', 'Uma fusão cósmica de benefícios que transformam a pele. Esfoliação eficaz com enzimas naturais.', 185.57, NULL, 'Tulipia', 'mascara', NULL, '/src/assets/products/tulipia/stellar-mask-enzimatica.png', ARRAY[]::text[], 100, 'HC-7044', true, false, false, ARRAY['profissional', 'Nano Ozônio Corporal', 'Ácido Poliglutâmico', 'Extrato de Uva', 'Extrato de Bromelina (Abacaxi)', 'Extrato de Papaína (Mamão)']::text[], ARRAY[]::text[], 'Nano Ozônio Corporal, Ácido Poliglutâmico, Extrato de Uva, Extrato de Bromelina (Abacaxi), Extrato de Papaína (Mamão)', NULL, '2026-03-09 17:10:24.434878+00', '2026-03-09 17:10:24.434878+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('938226a3-7768-4b04-9470-5a40a7dbc88a', 'Stellar Mask Matificante 100g', 'stellar-mask-matificante-100g-7045', 'Desenvolvida especialmente para regular a produção de oleosidade com ativo probiótico, mantendo a pele equilibrada e matificada, revelando uma aparência fresca e sem brilho excessivo.', 'Encontre a perfeita harmonia para uma pele suave e uniforme. Controle de oleosidade com ativo probiótico.', 185.57, NULL, 'Tulipia', 'mascara', NULL, '/src/assets/products/tulipia/stellar-mask-matificante.png', ARRAY[]::text[], 100, 'HC-7045', true, false, false, ARRAY['profissional', 'Extrato de Chá Verde', 'PCA de Zinco', 'Acne Less', 'Symbiocaps LA']::text[], ARRAY[]::text[], 'Extrato de Chá Verde, PCA de Zinco, Acne Less, Symbiocaps LA', NULL, '2026-03-09 17:10:24.749737+00', '2026-03-09 17:10:24.749737+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('ac6e43c7-3d37-4258-a3b8-10c168a2c318', 'Stellar Mask Rejuvenescedora 100g', 'stellar-mask-rejuvenescedora-100g-7046', 'Máscara rejuvenescedora desenvolvida para maximizar resultados em peles maduras. Previne o envelhecimento precoce, oferece alto poder de reparação, trata rugas e linhas finas, proporcionando efeito botox-like e alternativa segura ao retinol.', 'Máscara rejuvenescedora que maximiza resultados em peles maduras. Previne envelhecimento precoce com alto poder de reparação.', 185.57, NULL, 'Tulipia', 'mascara', NULL, '/src/assets/products/tulipia/stellar-mask-rejuvenescedora.png', ARRAY[]::text[], 100, 'HC-7046', true, false, false, ARRAY['profissional', 'NanoTech-C', 'Extrato de Gengibre', 'Hypskin®', 'Revinage®', 'Nano BTX Solution']::text[], ARRAY['Anti-idade', 'Exclusivo para profissional', 'Facial', 'Não indicado para gestantes', 'Rugas']::text[], 'NanoTech-C, Extrato de Gengibre, Hypskin®, Revinage®, Nano BTX Solution', NULL, '2026-03-09 17:10:24.749737+00', '2026-03-09 17:10:24.749737+00') ON CONFLICT (id) DO NOTHING;
