INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('bbe4ea3c-2135-42f9-a4ac-5344f1746869', 'Ultimate Estetic+ Nano Máscara Tensora de Ouro 250g', 'ultimate-estetic-nano-mascara-tensora-de-ouro-250g-7049', 'Uma máscara tensora mágica de alto impacto na revitalização cutânea e antienvelhecimento exclusiva. Formulada com Ouro, precioso elemento que catalisa o transporte dos nutrientes para o interior das células e tem papel importante na produção de colágeno e elastina. Enriquecida com Colágeno, Ginseng e Ginkgo Biloba para hidratação, nutrição e restauração da vitalidade da pele.', 'Máscara tensora mágica com Ouro para revitalização cutânea. Efeito lifting imediato e produção de colágeno/elastina.', 140.00, NULL, 'Tulipia', 'mascara', NULL, '/src/assets/products/tulipia/ultimate-estetic-mascara-ouro.png', ARRAY[]::text[], 100, 'HC-7049', true, false, false, ARRAY['profissional', 'Mica Dourada', 'Ginkgo Biloba', 'Extrato Glicólico de Hamamelis Virginiana L.', 'Colágeno Hidrolisado', 'Nanopartículas de Ouro', 'Extrato de Ginseng', 'Extrato de Sálvia', 'Alantoína']::text[], ARRAY['Anti-idade', 'Exclusivo para profissional', 'Facial', 'Hidratação', 'Indicado para todos os tipos de pele', 'Lifting', 'Nanotecnologia', 'Não indicado para gestantes']::text[], 'Mica Dourada, Ginkgo Biloba, Extrato Glicólico de Hamamelis Virginiana L., Colágeno Hidrolisado, Nanopartículas de Ouro, Extrato de Ginseng, Extrato de Sálvia, Alantoína', NULL, '2026-03-09 17:10:24.749737+00', '2026-03-09 17:10:24.749737+00') ON CONFLICT (id) DO NOTHING;
