INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('8ba89afc-0571-401e-b997-f164bea81bfb', 'Floraty Loção Amolecedora de Cravos 500ml', 'floraty-locao-amolecedora-de-cravos-500ml-7180', 'Floraty Amolecedor de Cravos contém AMP, um emoliente tão eficaz quanto a trietanolamina, porém sem os efeitos indesejáveis, tais como irritação e pinicação. Hidrata profundamente, promove emoliência e evita o ressecamento da pele. Indicado para todos os tipos de pele, inclusive sensíveis. Fórmula vegana e zero glúten.', 'Um dos grandes segredos de uma limpeza de pele perfeita é a emoliência bem realizada. Emoliente eficaz sem efeitos indesejáveis.', 141.43, NULL, 'Tulipia', 'limpeza-pele', NULL, '/src/assets/products/tulipia/floraty-amolecedor-cravos.png', ARRAY[]::text[], 100, 'HC-7180', true, false, false, ARRAY['profissional', 'Alantoína', 'AMP Ultra PC 2000', 'Extrato de Camomila']::text[], ARRAY[]::text[], 'Alantoína, AMP Ultra PC 2000, Extrato de Camomila', NULL, '2026-03-09 17:10:25.37629+00', '2026-03-09 17:10:25.37629+00') ON CONFLICT (id) DO NOTHING;
INSERT INTO products (id, name, slug, description, short_description, price, compare_at_price, brand, category, subcategory, image_url, images, stock, sku, is_active, is_promotion, is_new, tags, benefits, ingredients, how_to_use, created_at, updated_at) VALUES ('a516d0f2-8dbf-44dd-a42f-b5866a3f4c6d', 'Floraty Creme Esfoliante Apricot 200g', 'floraty-creme-esfoliante-apricot-200g-7181', 'O Creme Esfoliante Apricot possui textura suave e cremosa, que desliza facilmente sobre a pele, deixando-a visivelmente mais macia, iluminada e com toque aveludado. Suas microesferas promovem uma esfoliação gentil, auxiliando na remoção de células mortas e impurezas, sem causar irritações. Rico em ácidos graxos essenciais Ômega 9 e Ômega 6, oferece emoliência intensa.', 'Esfoliante físico de textura suave e cremosa. Microesferas removem impurezas deixando a pele sedosa e radiante.', 141.43, NULL, 'Tulipia', 'limpeza-pele', NULL, '/src/assets/products/tulipia/floraty-esfoliante-apricot.png', ARRAY[]::text[], 100, 'HC-7181', true, false, false, ARRAY['profissional', 'Semente de Apricot (Damasco)', 'Ômega 9 (Ácido Oleico)', 'Ômega 6 (Ácido Linoleico)', 'Vitamina B']::text[], ARRAY['Creme', 'Esfoliação', 'Exclusivo para profissional', 'Facial e Corporal', 'Higienização', 'Indicado para todos os tipos de pele', 'Livre de Parabeno', 'Vegano']::text[], 'Semente de Apricot (Damasco), Ômega 9 (Ácido Oleico), Ômega 6 (Ácido Linoleico), Vitamina B', NULL, '2026-03-09 17:10:25.37629+00', '2026-03-09 17:10:25.37629+00') ON CONFLICT (id) DO NOTHING;
